{
  "title": "人工智能发展简史",
  "chapters": [
    {
      "title": "引言：AI为何重要？",
      "pages": [
        {
          "title": "课程定位与学习目标",
          "bullets": [
            "理解AI演进的阶段性特征与驱动因素",
            "掌握关键里程碑事件、人物与技术突破",
            "建立对当前大模型热潮的历史纵深认知"
          ],
          "notes": "开场提问：‘ChatGPT是突然出现的吗？’ 引导学生意识到技术爆发必有长期积累；强调本讲目标不是罗列年份，而是理解‘为什么此时此地发生此事’。"
        }
      ]
    },
    {
      "title": "奠基与起伏：1950s–1980s",
      "pages": [
        {
          "title": "萌芽期（1950s）：思想诞生",
          "bullets": [
            "1950年图灵提出‘机器能否思考’，设计图灵测试作为智能判据",
            "1956年达特茅斯会议正式命名‘Artificial Intelligence’",
            "早期程序：逻辑理论家（首个人工智能程序）、感知机（首个神经网络模型）"
          ],
          "notes": "过渡语：‘一个学科的诞生，往往始于一场会议和一篇论文’；举例图灵测试：让人类裁判通过文字对话判断对方是人还是机器。"
        },
        {
          "title": "第一次寒冬（1970s）：期望与现实的落差",
          "bullets": [
            "专家系统初现：MYCIN（医疗诊断）、DENDRAL（化学分析）",
            "1973年莱特希尔报告批评AI‘未兑现通用智能承诺’",
            "英美政府大幅削减资助，学术热情骤降"
          ],
          "notes": "讲解提示：用‘过山车’比喻——高峰（专家系统成功）→断崖（资金撤出）；强调‘寒冬’不等于停滞，而是反思转向。"
        },
        {
          "title": "专家系统时代（1980s）：知识即力量",
          "bullets": [
            "核心范式：将人类专家经验编码为‘if-then’规则",
            "XCON系统为DEC公司年省4000万美元，验证商业价值",
            "日本第五代计算机计划激发全球AI竞赛，但最终未达预期"
          ],
          "notes": "举例说明规则局限性：‘如果发烧且白细胞升高→细菌感染’，但无法处理模糊或矛盾证据；过渡到下一章：‘当知识难以穷举，路在何方？’"
        }
      ]
    },
    {
      "title": "范式转移：1990s–2010s",
      "pages": [
        {
          "title": "机器学习崛起（1990s）：从规则到数据",
          "bullets": [
            "符号主义退潮，统计学习成为主流方法论",
            "SVM（1995）、随机森林（1997）奠定现代分类基础",
            "深蓝击败卡斯帕罗夫（1997）：暴力搜索+领域优化的胜利"
          ],
          "notes": "对比强调：深蓝≠通用AI，它不会下围棋、也不会写诗；它是工程化巅峰，而非认知突破；为深度学习埋下伏笔。"
        },
        {
          "title": "深度学习爆发（2010s）：算力、数据与算法共振",
          "bullets": [
            "2012年AlexNet引爆图像识别革命（错误率降11%）",
            "GPU并行计算+ImageNet大数据集+ReLU/ Dropout等关键技术突破",
            "AlphaGo（2016）攻克围棋：蒙特卡洛树搜索 + 深度神经网络"
          ],
          "notes": "用数字强化记忆：ImageNet含1400万标注图像；AlphaGo每秒评估约10万棋局；强调‘三要素缺一不可’。"
        }
      ]
    },
    {
      "title": "生成式AI时代：2020s至今",
      "pages": [
        {
          "title": "大模型元年（2022–2023）：ChatGPT现象",
          "bullets": [
            "ChatGPT发布5天破百万用户，2个月月活破亿",
            "GPT-4（2023）通过律师考试、生物奥赛等专业测试，超越人类均值",
            "Transformer架构成为统一基座：文本、代码、多模态持续扩展"
          ],
          "notes": "类比教学：‘如果说AlexNet是AI的iPhone时刻，ChatGPT就是App Store时刻’——生态真正开放；提醒学生注意‘涌现能力’非预设。"
        },
        {
          "title": "中国大模型图谱（2023–2025）",
          "bullets": [
            "百度文心一言（2023.3）、阿里通义千问（2023.4）、智谱ChatGLM（开源路线）",
            "深度求索DeepSeek聚焦代码与数学推理，2024年发布DeepSeek-V2/V3",
            "2025趋势：开源模型性能逼近闭源，Qwen2、GLM-4、DeepSeek-R1形成技术三角"
          ],
          "notes": "强调工程视角：国产模型并非简单复刻，而是在训练框架、中文语料、推理优化上差异化突破；可展示Hugging Face模型排行榜实时截图。"
        }
      ]
    },
    {
      "title": "挑战与未来：不止于技术",
      "pages": [
        {
          "title": "现实挑战：幻觉、能耗与对齐",
          "bullets": [
            "幻觉（Hallucination）：模型自信生成错误事实，如虚构论文或法律条文",
            "单次大模型训练碳排放≈5辆汽车终身排放（约284吨CO₂）",
            "对齐问题（Alignment）：如何确保AI目标与人类真实意图一致？"
          ],
          "notes": "举例幻觉：‘告诉学生某篇不存在的IEEE论文被引用2000次’；用‘自动驾驶刹车’类比对齐——不是‘按指令刹车’，而是‘为保护生命而刹车’。"
        },
        {
          "title": "前沿方向：走向更可靠、更自主的AI",
          "bullets": [
            "高效小模型：TinyLLM、Phi-3，适配手机/嵌入式设备",
            "具身智能：机器人+大模型，实现物理世界交互（如Figure 01）",
            "AI Agent：能自主规划、调用工具、迭代修正的智能体（Devin、Manus）"
          ],
          "notes": "总结升华：AI正从‘回答问题’走向‘解决问题’；呼应开头——历史不是循环，而是螺旋上升；留思考题：‘你希望自己的第一个AI Agent帮你做什么？’"
        }
      ]
    },
    {
      "title": "结语：技术史中的工程师思维",
      "pages": [
        {
          "title": "回顾与启示",
          "bullets": [
            "AI发展非线性：繁荣—寒冬—再繁荣，受技术、资本、社会期待共同塑造",
            "重大突破常源于交叉：数学（概率/优化）、硬件（GPU）、数据（互联网）",
            "软件工程师的核心能力：理解范式迁移，选择合适工具，警惕技术光环"
          ],
          "notes": "收尾金句：‘学历史不是为了背年代，而是为了在下一个拐点到来时，你能听懂技术的胎动’；预告下节课：《大模型工作原理：从Tokenizer到RLHF》。"
        }
      ]
    }
  ]
}
